mapper.select:
select jwo.id, jwo.factory_id, f.factory_name, jwo.number, jwo.style_number, jwo.category_id, jc.category, jwo.quantity, jwo.created_date, jwo.flag from job_work_order jwo left join factory f on jwo.factory_id = f.id and f.flag = 0 left join job_category jc on jwo.category_id = jc.id and jc.flag = 0
jwo.flag = #{flag}
and jwo.factory_id = #{factoryId}
and jwo.number like concat('%', #{number}, '%')
and jwo.style_number like concat('%', #{styleNumber}, '%')
and jwo.category_id = #{categoryId}
and jwo.created_date between #{startDate} and #{endDate}
and jwo.created_date = #{startDate}
and jwo.created_date <= #{endDate}
and jwo.created_date = curdate()
order by jwo.created_date desc, f.factory_name collate utf8mb4_zh_0900_as_cs asc, jwo.number asc
